import { describe, expect, it } from 'vitest';
import {
  kmsToFractionC,
  kinematicRedshift,
  cosmologicalRedshift,
  combinedRedshift,
  redshiftColor,
  computeRedshift,
} from './doppler-redshift';

// ─── kmsToFractionC ────────────────────────────────────────────────

describe('kmsToFractionC', () => {
  it('converts 299800 km/s to approximately 1.0', () => {
    const beta = kmsToFractionC(299800);
    expect(beta).toBeCloseTo(1.0, 2);
  });

  it('converts 300 km/s to approximately 0.001', () => {
    const beta = kmsToFractionC(300);
    expect(beta).toBeCloseTo(0.001, 3);
  });
});

// ─── kinematicRedshift ─────────────────────────────────────────────

describe('kinematicRedshift', () => {
  it('returns z = 0 for β = 0 (stationary)', () => {
    expect(kinematicRedshift(0)).toBe(0);
  });

  it('returns z ≈ 0.732 for β = 0.5 (receding)', () => {
    const z = kinematicRedshift(0.5);
    expect(z).toBeCloseTo(0.732, 3);
  });

  it('returns z ≈ -0.423 for β = -0.5 (approaching, blueshift)', () => {
    const z = kinematicRedshift(-0.5);
    expect(z).toBeCloseTo(-0.423, 3);
  });

  it('receding source gives positive z (redshift)', () => {
    expect(kinematicRedshift(0.1)).toBeGreaterThan(0);
    expect(kinematicRedshift(0.9)).toBeGreaterThan(0);
  });

  it('approaching source gives negative z (blueshift)', () => {
    expect(kinematicRedshift(-0.1)).toBeLessThan(0);
    expect(kinematicRedshift(-0.9)).toBeLessThan(0);
  });
});

// ─── cosmologicalRedshift ──────────────────────────────────────────

describe('cosmologicalRedshift', () => {
  it('Proxima Centauri (4.24 ly) has negligible z', () => {
    const z = cosmologicalRedshift(4.24);
    expect(z).toBeCloseTo(0, 5);
    expect(Math.abs(z)).toBeLessThan(1e-6);
  });

  it('M87* (53.49 million ly) has z ≈ 0.003654', () => {
    const z = cosmologicalRedshift(53.49e6);
    expect(z).toBeCloseTo(0.003654, 4);
  });
});

// ─── combinedRedshift ──────────────────────────────────────────────

describe('combinedRedshift', () => {
  it('both zero yields zero', () => {
    expect(combinedRedshift(0, 0)).toBe(0);
  });

  it('z_kin=0.1 + z_cosmo=0.01 yields z ≈ 0.111', () => {
    const z = combinedRedshift(0.1, 0.01);
    expect(z).toBeCloseTo(0.111, 3);
  });
});

// ─── redshiftColor ─────────────────────────────────────────────────

describe('redshiftColor', () => {
  it('z = 0 returns neutral white', () => {
    const color = redshiftColor(0);
    expect(color).toEqual({ r: 255, g: 255, b: 255 });
  });

  it('z > 0 returns reddish tint (r >= 255, b < 255)', () => {
    const color = redshiftColor(0.5);
    expect(color.r).toBe(255);
    expect(color.b).toBeLessThan(255);
  });

  it('z < 0 returns bluish tint (b >= 255, r < 255)', () => {
    const color = redshiftColor(-0.5);
    expect(color.b).toBe(255);
    expect(color.r).toBeLessThan(255);
  });
});

// ─── Known Stars ───────────────────────────────────────────────────

describe('known stars', () => {
  it("Barnard's Star: RV = -110.6 km/s → blueshift z ≈ -0.000369", () => {
    const beta = kmsToFractionC(-110.6);
    const z = kinematicRedshift(beta);
    expect(z).toBeCloseTo(-0.000369, 5);
  });

  it('Proxima Centauri: RV = -22.2 km/s → blueshift z ≈ -0.0000741', () => {
    const beta = kmsToFractionC(-22.2);
    const z = kinematicRedshift(beta);
    expect(z).toBeCloseTo(-0.0000741, 6);
  });
});
